+import Foundation
+
+struct WhisperSegment: Equatable, Sendable {
+    var text: String
+}
+
+final class SpeechTranscriber {
+    private static let artifacts = [
+        "[BLANK_AUDIO]",
+        "[NO_SPEECH]",
+        "(blank audio)",
+        "(no speech)",
+        "[MUSIC]",
+        "[APPLAUSE]",
+        "[LAUGHTER]"
+    ]
+
+    private let catalogByID: [String: SpeechModelDescriptor]
+    private let whisperRuntime: any WhisperRuntimeLoading
+
+    init(
+        catalog: [SpeechModelDescriptor],
+        whisperRuntime: any WhisperRuntimeLoading
+    ) {
+        catalogByID = Dictionary(uniqueKeysWithValues: catalog.map { ($0.id, $0) })
+        self.whisperRuntime = whisperRuntime
+    }
+
+    func transcribe(samples: [Float], modelID: String?) async -> String? {
+        guard !samples.isEmpty else {
+            return nil
+        }
+
+        guard let modelID, let model = catalogByID[modelID] else {
+            return nil
+        }
+
+        switch model.backend {
+        case .whisper:
+            do {
+                guard let segments = try await whisperRuntime.transcribe(audioSamples: samples) else {
+                    return nil
+                }
+
+                let joined = segments
+                    .map(\.text)
+                    .joined(separator: " ")
+                let cleaned = Self.cleanedTranscription(from: joined)
+                return cleaned.isEmpty ? nil : cleaned
+            } catch {
+                return nil
+            }
+        case .fluidAudio:
+            return nil
+        }
+    }
+
+    private static func cleanedTranscription(from text: String) -> String {
+        let withoutArtifacts = artifacts.reduce(text) { partialResult, artifact in
+            partialResult.replacingOccurrences(of: artifact, with: "")
+        }
+
+        return withoutArtifacts
+            .replacingOccurrences(of: #"\s+"#, with: " ", options: .regularExpression)
+            .trimmingCharacters(in: .whitespacesAndNewlines)
+    }
+}

